// ospreyLexerInit initializes any static state used to implement ospreyLexer. By default the
// static state used to implement the lexer is lazily initialized during the first call to
// NewospreyLexer(). You can call this function if you wish to initialize the static state ahead
// of time.
func OspreyLexerInit() {
	staticData := &OspreyLexerLexerStaticData
	staticData.once.Do(ospreylexerLexerInit)
}

// NewospreyLexer produces a new lexer instance for the optional input antlr.CharStream.
func NewospreyLexer(input antlr.CharStream) *ospreyLexer {
	OspreyLexerInit()
	l := new(ospreyLexer)
	l.BaseLexer = antlr.NewBaseLexer(input)
	staticData := &OspreyLexerLexerStaticData
	l.Interpreter = antlr.NewLexerATNSimulator(l, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	l.channelNames = staticData.ChannelNames
	l.modeNames = staticData.ModeNames
	l.RuleNames = staticData.RuleNames
	l.LiteralNames = staticData.LiteralNames
	l.SymbolicNames = staticData.SymbolicNames
	l.GrammarFileName = "osprey.g4"
	// TODO: l.EOF = antlr.TokenEOF

	return l
}

